var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"서쪽 침식쐐기 정리 끝!","JPN":"西の侵食楔、片付け完了！","ENG":"Corrupted Wedge in the west, cleared!","TWN":"西邊的侵蝕釘清除完畢！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아 아- 사부, 이제 잘 들리지?","JPN":"あ、あ。師匠、ばっちり聞こえるでしょ？","ENG":"Check, check. Master, you hear me now?","TWN":"喂喂，師父，聽得清楚嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"통신 문제는 해결됐군. 설치 작업을 시작해도 되겠어.","JPN":"通信の問題は解決したな。設置作業を始めてもよいだろう。","ENG":"Good, the comms issue is fixed. We can start the installation.","TWN":"通訊問題解決了，可以開始安裝了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"동쪽 현장 정리도 끝났다.","JPN":"東の現場も片付いた。","ENG":"East site's cleared too.","TWN":"東邊也清理完畢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대도 고생 많았네.","JPN":"そなたもご苦労だった。","ENG":"Good work.","TWN":"你也辛苦了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그런데 걸어서 보고하러 온 건가? 앤디처럼 통신기를 써도 될 텐데 말이지.","JPN":"ところで、報告のためにわざわざ歩いて来たのか？　アンディーのように通信機でも構わんのだが。","ENG":"But you came all the way here to report? You could've just used a phone like Andy.","TWN":"不過你還特地走回來報告嗎？怎麼不像安狄一樣用手機回報就好？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"됐어. 전자기기는 내 손에 영 안 맞거든.","JPN":"いい。電子機器とは相性が悪いからな。","ENG":"Forget it. Gadgets and I don't get along.","TWN":"不，我跟電子產品不太合。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"맞아, 사부. 지수 언니 같은 어르신한테 그런 건 무리라고.","JPN":"そうだよ。シノさんみたいなおばあさんには無理だよ。","ENG":"Exactly, Master. Expecting a granny like Jisoo to handle tech is pushing it.","TWN":"對啊，師父。像智秀姊那樣的阿姨不會用3Ｃ啦。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"죽고 싶나, 꼬맹이?","JPN":"ガキ、死にたいのか？","ENG":"You want a piece of me, kid?","TWN":"想死嗎，小鬼？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이제 그렇게 겁줘도 안 쫄아! 자기도 직원이면서 맨날 장비 조정 일은 떠넘기기만 하잖아!","JPN":"もう脅してもビビってやらないもんね！　自分だって社員のくせに、装備の調整とかいつも私に押しつけて！","ENG":"Hah! I'm not scared of you anymore! You're an employee too, but you always dump the gear work on us!","TWN":"我現在不怕你喔！你身為員工，卻總是把調整設備的工作推給我！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"연구소에서 반년 넘게 일한 사람이 폰도 못 만지는 기계치라니. 누가 믿겠어? 노력하는 시늉도 안 하잖아.","JPN":"研究所で半年以上働いてる人が携帯すら扱えない機械音痴ー？　そんなの信じるかっての。努力してる風でもないしさ。","ENG":"How does someone working here for six months still not know how to use a phone? You don't even pretend to try!","TWN":"在研究室工作半年多，說你是連手機都不會用3C白癡，誰會信？你連裝都不裝一下！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"정 원한다면 노력해주지.","JPN":"そんなに望むなら努力してやる。","ENG":"If you really want me to try, I'll do it.","TWN":"你想要的話，我是可以努力看看。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"내가 너희의 비싼 장비를 쓸모없는 깡통으로 만들어버려도 감당할 수 있다면 말이야.","JPN":"私がお前たちの高い装備をスクラップにしてもいいならな。","ENG":"That is, if you can handle me turning all your fancy gear into junk.","TWN":"前提是你們能承受我把珍貴的設備變成廢鐵的話。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"흥, 일하기 싫어서 일부러 고장내는 게 뻔하지. 누가 모를 줄 알고?","JPN":"ふん、働きたくなくてわざと壊すに決まってるよ。バレバレなんだから！","ENG":"Hmph! You'd just break it on purpose to get out of work. You think I don't know?","TWN":"哼，你只是不想工作故意弄壞而已。誰不知道？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"버튼 하나 누른 정도로 장비를 박살내는 인간이 세상에 실존할 리 없잖아!","JPN":"ボタン押しただけで装備を壊すような指なんて、実在するわけがない！","ENG":"No way someone's fingers can wreck a machine with one button press!","TWN":"世界上怎麼可能有人，只按一個按鈕就把設備弄壞！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"호오? 네 사부의 소중한 발명품이 내 손가락에 박살 나는 걸 다시 보고 싶단 뜻인가?","JPN":"ほお？　お前の師匠の大事な発明品が私の指でぶっ壊れるところをもう一度目にしたいとでも？","ENG":"Oh? Want to see your master's precious inventions crushed under my fingertips again?","TWN":"喔？你很想再看到你師父珍貴的發明在我手指下變成廢鐵嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어디 해보시지! 이번에야말로 무슨 속임수를 쓴 건지 간파해주겠어!","JPN":"やれるもんならやってみなよ！　今度こそ、どういうトリック使ってるのか見抜いてやる！","ENG":"Go ahead! This time I'll figure out your trick!","TWN":"來呀！這次我一定要看穿破你的手腳！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"크흠, 내 발명품으로 검증하는 건 그만 두지.","JPN":"ゴホン、某の発明品で検証するのはやめてくれぬか。","ENG":"Ahem. Enough testing my inventions for this.","TWN":"咳咳，還是別拿我的發明來做實驗吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"지수 양은 지난 반년 간 충분히 노력했네. 너무 몰아붙이는 건 좋지 않아.","JPN":"シノ君はこの半年間、十分努力してくれた。あまり追いつめるのはよくない。","ENG":"Jisoo's done plenty these past six months. No need to push her.","TWN":"智秀這半年已經很努力了，別再逼她了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"너무해, 사부! 난 사부 편인데에-!","JPN":"ひどいよ、師匠！　私は師匠の味方なのに～！","ENG":"Come on, Master! I was on your side!","TWN":"師父，你怎麼這樣！我是在幫你欸！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"쯧.","JPN":"ちっ。","ENG":"Tsk.","TWN":"嘖。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그러고 보니, 근래 제대로 쉬지도 못하고 일만 했군.","JPN":"そういえば、近頃は仕事詰めでまともな休暇も取れていなかったな。","ENG":"Come to think of it, we've all been working non-stop lately.","TWN":"這麼說來，最近我們都沒好好休息，一直在工作。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"장치 조율은 나 혼자로 충분하니, 두 사람은 간만에 도시로 쇼핑이나 다녀오는 게 어떻겠나?","JPN":"装備の調整は某一人で十分できる。2人は久々に都市で買い物でもして来たらどうだ？","ENG":"I can handle the adjustments alone. Why don't you two head into town for a shopping break?","TWN":"裝置的調整我來就好，你們兩個去城裡逛逛吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"진짜?! 그래도 돼?","JPN":"本当！？　いいの？","ENG":"Really?! You mean it?","TWN":"真的嗎？！可以嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L38_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"오는 길에 내 군것질거리도 챙겨주면 좋고.","JPN":"帰りに某のおやつも頼む。","ENG":"Just bring back my snacks on the way.","TWN":"可以的話，回來時順便幫我帶點零食。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"응! 사부가 좋아하는 땅콩 한 트럭 사올게!","JPN":"うん！　師匠が好きなピーナッツ、トラック1台分買ってくるね！","ENG":"Sure! I'll bring back a truckload of peanuts just for you!","TWN":"好！我幫你買一卡車你愛的花生！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"있다- 있어. 노동으로 지친 피부를 살려줄 탄력에센스!","JPN":"あったあった！　労働で疲れた肌をケアするハリ感アップエッセンス！","ENG":"Look what I've got here… Firming essence for my poor, overworked skin!","TWN":"喔，找到了。可以拯救疲勞肌膚的緊緻精華液！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"언제 돌아올지 모르니까 몇 개 더 챙길까?","JPN":"いつまた来れるか分からないし、買い溜めしとこうかな？","ENG":"Should I grab a few more? Who knows when I'll be back here.","TWN":"不知道什麼時候會再來，要多買幾個嗎？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어르신 것도 살래?","JPN":"おばあさんも要る？","ENG":"Want one too, granny?","TWN":"阿姨也要買嗎？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"도시로 오니 흥분한 강아지가 따로 없군.","JPN":"都市に来ると、まるではしゃぎ回る犬のようだな。","ENG":"You're like an excited puppy in the city.","TWN":"一來到城市，就興奮得像隻小狗。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"당연히 흥분되지! 이 동네에 드디어 멀쩡한 쇼핑몰이 생겼는걸?","JPN":"当たり前でしょ！　やっとこの街にまともなショッピングモールができたんだもん！","ENG":"Of course I'm excited! We finally have a proper mall in town!","TWN":"當然興奮啦！這裡終於開了間像樣的購物中心！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이 화장품 진열대 좀 봐! 더 이상 천연보습제 만드느라 산에 대추 따러 다닐 일도 없어졌다고.","JPN":"このコスメコーナー見て！　もう天然保湿液作るためにわざわざ山にナツメを採りにいかなくていいんだよ！","ENG":"Look at this cosmetics aisle! No more foraging in the hills for wild fruit to make homemade lotion!","TWN":"你看這化妝品陳列櫃！以後再也不用去山裡摘紅棗做成天然保濕乳液了。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"2년만에 인프라가 이 정도로 좋아진 건 다 도시관리국 덕분이라니까? 찬양하라! 관리국!","JPN":"たった2年でこれほどインフラが整ったのは、全部都市管理局のおかげ！　管理局さまさまだよ！","ENG":"All this new infrastructure in just two years thanks to the City Management! Praise be! The Administration!","TWN":"短短兩年內，基礎設施變得這麼好，都是因為城市管理局！讚揚管理局！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L1_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…관리국이 아니었다면, 확실히 사람 밖에 없던 시골이 이 정도 구색을 갖추긴 힘들었겠지.","JPN":"……確かに管理局じゃなければ、何の取り柄もないこんな田舎の環境をここまで発展させるのは難しかっただろう。","ENG":"…If not for the Administration, this place would still be nothing but farmland.","TWN":"…如果沒有管理局，這個只有人煙的鄉下，也很難有現在的樣子。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"생활권 확장을 염두에 두고, 내년엔 챔버의 기상조절장치도 들여올 거라더군.","JPN":"生活圏を拡張させるために、来年はチェンバーの気象調節装置も導入するらしいな。","ENG":"They're even bringing in Chamber's Weather Control System next year to expand the settlement.","TWN":"而且為了擴大生活圈，明年還要引進強巴的氣候調節裝置。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"앗, 그거 알아? 기상조절장치는 사부가 만들었다는 거!","JPN":"あっ、知ってる？　その気象調整節置って、師匠が作ったんだよ！","ENG":"Oh, did you know? Master invented the Weather Control System!","TWN":"啊，你知道嗎？那個氣候調節裝置是師父做的！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"매달 받고 있다던 개런티의 출처가 그거였나?","JPN":"毎月もらっているという手当の出所はそれだったか。","ENG":"So that's where his stipend comes from.","TWN":"每個月領的錢就是從那裡來的嗎？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"오, 의외네. 헛소리 말라고 할 줄 알았는데 바로 수긍하다니.","JPN":"お、なんか意外。嘘つくなって言うと思ったのにすんなり頷くなんて。","ENG":"Huh, I thought you'd call that nonsense. Didn't think you'd buy it so quick.","TWN":"喔，真意外。我以為你會說我在吹牛，沒想到竟然沒反駁我。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"너처럼 2년씩이나 같이 지내지 않아도 대강은 알 수 있어.","JPN":"お前のように2年も共に暮らさなくてもだいたい分かるさ。","ENG":"I don't need to stick with him for two years like you to figure it out.","TWN":"我跟你不一樣，我不需要花兩年的時間就能大致知道他是什麼樣子。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"서생이 기상조절장치쯤 되는 물건도 혼자서 발명할 수 있는 인간이란 걸 말이야.","JPN":"気象調節装置ほどのものでも、シヨウなら一人で発明できてしまうということぐらい。","ENG":"Anyone can tell Seosaeng could invent something like that all by himself.","TWN":"書生就是那種能一個人發明氣候調節裝置的人。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사계절이 돌아오면 식물 종자도 수 백 가지를 들여와서 심을 거래.","JPN":"四季が復活したら、植物の種も数百種類を植える予定なんだって。","ENG":"Once the seasons are back, they're bringing in hundreds of plant seeds too.","TWN":"等四季輪轉，他們還會引進數百種植物種子來種植。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"우리 집은 한참 먼 외곽이라 혜택은 못 받겠지만, 내년부터 구호소 애들이랑 꽃구경은 갈 수 있을지도?","JPN":"うちは都心から離れすぎてるから大した得はないだろうけど、来年からは保護施設の子どもたちとお花見ぐらいはできるかも。","ENG":"Our place is way out in the sticks, so we won't see much of it. But at least we'll get to take the kids from the shelter to see the flowers.","TWN":"雖然我家在很遠的郊外，享受不到這個福利。但從明年開始，我就可以帶著收容所的孩子去賞花了。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"넌 챔버에서 태어나 자랐다고 했지.","JPN":"お前はチェンバーで生まれ育ったと言ったな。","ENG":"You said you used to live in Chamber, right?","TWN":"你說你原本住在強巴？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"도시의 문물을 그렇게나 좋아하는 녀석이 왜 이런 곳까지 와서 서생을 돕고 있는 거냐?","JPN":"都市の文明がそんなに好きなやつが、なぜこの僻地まで来てショウを手伝っている？","ENG":"So why's a city girl like you sticking around here helping Seosaeng?","TWN":"一個這麼喜歡城市的人，為什麼要來這種地方幫書生？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"화장품 같은 건 있으면 좋고 없으면 없는 대로 사는 거잖아.","JPN":"化粧品なんて、あったらいいけど、ないならないで生きていけるでしょ。","ENG":"Stuff like cosmetics are nice to have but not essential.","TWN":"化妝品這種東西，有也好，沒有也沒差。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부가 나한테 그런 존재는 아니니까.","JPN":"でも師匠は私にとって、そういう存在じゃないから。","ENG":"Master's not something I could just do without.","TWN":"但師父對我來說不是可有可無的。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"사랑인가?","JPN":"恋か？","ENG":"Do you love him?","TWN":"是愛情嗎？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭐래! 생명의 은인이니까 돕는 거라고!","JPN":"はあ？　命の恩人だから手伝ってるの！","ENG":"What?! No! He saved my life! That's why I help him!","TWN":"胡說什麼！因為他是我的救命恩人，所以我才幫他！"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그런가.","JPN":"そうか。","ENG":"I see.","TWN":"是喔。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"조금이라도 그런 마음을 품고 있다면, 각오하는 편이 좋을 거야.","JPN":"少しでもやつに気があるなら、覚悟したほうがいい。","ENG":"If you do feel anything more than that, you'd better be ready.","TWN":"如果你對他有一點點感情，最好有心理準備。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"지금 서생이 하고 있는 건, 언제 죽어도 이상하지 않을 만큼 무모한 실험이니까.","JPN":"やつが今やっていることは、いつ死んでもおかしくないほど無謀な実験だ。","ENG":"What he's doing now is reckless enough to get him killed at any moment.","TWN":"書生現在正在做的實驗，是隨時都可能喪命的。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…알아.","JPN":"……分かってる。","ENG":"…I know.","TWN":"…我知道。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그렇게나 예쁜데- 목숨 걸고 찾을 만도 하지.","JPN":"あんな美人だもんね～命がけで探すのも分かるよ。","ENG":"But with a beauty like that, it's worth risking everything, right?","TWN":"長那麼漂亮，確實值得他拿性命去找。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"누가 예쁘다고?","JPN":"誰のことだ？","ENG":"Who's beautiful?","TWN":"你說誰漂亮？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아니… 별 얘기 아냐.","JPN":"ううん……なんでもない。","ENG":"Ah… Forget it. It's nothing.","TWN":"沒有…沒什麼。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부가 왜 그렇게까지 과거에 집착했는지, 그 이유를 알 것 같아서.","JPN":"ただ、師匠が過去に執着する理由が、なんとなく分かる気がしてね。","ENG":"I think I kinda get why Master's so obsessed with the past.","TWN":"我好像有點明白，為什麼師父會對過去這麼執著了。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그러고 보니 넌 녀석과 함께 과거에 가본 적이 있다고 했지.","JPN":"そういえばお前はやつと共に過去に行ったことがあったんだったな。","ENG":"You said you've actually gone back with him once.","TWN":"這麼說來，你說你跟他一起回到過去過。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"거기서 뭘 봤던 거야?","JPN":"そこで何を見た？","ENG":"What did you see there?","TWN":"你在那裡有看到什麼嗎？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이면세계랑 침식체들…","JPN":"裏世界と侵食体……","ENG":"The Counterside, some C.O.s…","TWN":"異界和侵蝕體…"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그리고 사부를 알아보는 어떤 여자를 만났어.","JPN":"あと、師匠を知っている女の人に会ったよ。","ENG":"And someone who recognized Master.","TWN":"還有一個認識師父的人。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아마 사부가 매일 밤 꿈에서 봤다는 그 사람이겠지.","JPN":"多分、毎晩師匠の夢に出てくるって人なんだと思う。","ENG":"Probably the person he keeps seeing in his dreams.","TWN":"應該就是師父每天晚上在夢裡看到的那個人吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"대강 알겠군.","JPN":"だいたい分かった。","ENG":"I get it now.","TWN":"大致明白了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"무언가 중요한 걸 잃어버린 사람은 보통 과거를 쫓게 되기 마련이니까.","JPN":"何か大切なものを失った人は、過去を追い求めるものだ。","ENG":"People who lose something that important always chase the past.","TWN":"失去了重要東西的人，通常都會追尋過去。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"누구라도 그러겠지. 아마도.","JPN":"誰でもそうでしょ、多分。","ENG":"Yeah. Who wouldn't, really.","TWN":"換作是誰都一樣吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"넌 그걸 알면서도 계속 여기 머무는 건가? 타인의 목적을 위해 자기 목숨까지 내놓으면서?","JPN":"お前はそれを知ってここにいるのか？　他人の目的のために自分の命をかけてまで？","ENG":"Yet you stay here, risking your life for someone else's goal?","TWN":"你明知道這一點，卻還是留在這裡嗎？為了別人的目標，甚至不惜犧牲自己的性命？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"난 사부처럼 기억을 잃진 않았지만 소중한 과거도 딱히 없거든.","JPN":"私は師匠みたいに記憶を失ったわけじゃないけど、大切な過去の記憶ってあまりないんだ。","ENG":"I haven't lost my memories, but I don't have much of a past worth chasing either.","TWN":"我雖然沒有失去記憶，但我沒什麼珍貴的回憶。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"나한테 중요한 건 지금 여기에 다 있으니까.","JPN":"私にとって大切なものは、今ここに在るものが全部だから。","ENG":"Everything that matters to me is right here, right now.","TWN":"對我來說，重要的東西現在都在這裡。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"돌아가는 길에 아이스크림 가게나 들르지.","JPN":"帰りにアイスの店にでも寄るか。","ENG":"Let's grab some ice cream on the way back.","TWN":"回程的時候，我們去冰淇淋店吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어르신이 쏘는 거야?","JPN":"おばあさんのおごり？","ENG":"You're paying, granny?","TWN":"阿姨請客嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…그래.","JPN":"……ああ。","ENG":"…Sure.","TWN":"…對。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"앗싸! 사랑해! 어르신!","JPN":"やった！　おばあさん大好き！","ENG":"Yes! Love you, granny!","TWN":"哇！好棒喔！阿姨我愛你！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그리고 다시 한번 더 어르신이라고 부르면, 저 다리 아래 강물로 던져주지.","JPN":"あと一度でもおばあさんと呼んでみろ。あの橋の下の川に放り投げてやる。","ENG":"Call me granny again, and I'll throw you down in the river.","TWN":"你再叫我一次阿姨，我就把你丟到那座橋下的河裡。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"싫은데? 통신기 쓸 수 있게 되면 한 번 생각은 해볼…","JPN":"いやだけど？　通信機使えるようになったら、検討はしてみ……","ENG":"Nope! Maybe I'll stop when you learn to use a pho–","TWN":"誰管你。除非你會用手機，我再考慮考…"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"꺄아! 아직 어르신이라고 안 했잖아!","JPN":"きゃ！　まだおばあさんって言ってない！","ENG":"Kyaaaah! I didn't even call you granny yet!","TWN":"欸！我又沒叫你阿姨！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"VOICE_NPC_NULL_NULL","text":{"KOREA":"하늘에 먹이 잔뜩 꼈네.","JPN":"空が墨雲に覆われてる。","ENG":"The sky's choked with clouds.","TWN":"天空烏雲密布。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"VOICE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"VOICE_NPC_NULL_NULL","text":{"KOREA":"곧 비가 사납게 쏟아지겠지.","JPN":"もうすぐ激しく降り出すわね。","ENG":"Rain's going to pour down hard soon.","TWN":"很快就會下起傾盆大雨吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"VOICE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그렇겠지.","JPN":"そうだな。","ENG":"Yeah.","TWN":"是啊。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"VOICE_NPC_NULL_NULL","text":{"KOREA":"왜 아직도 거기 있어? 이게 꿈이란 걸 알고 나면 늘 깨어나려고 도망쳤잖아.","JPN":"どうしてまだそこにいるの？　いつもなら夢だって分かったとたんに、目覚めようとして逃げるのに。","ENG":"Why are you still here? You always ran when you realized this was a dream.","TWN":"你為什麼還在那裡？知道這是夢之後，你不是總想逃走嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"VOICE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"연화.","JPN":"レンカ。","ENG":"Yeonhwa.","TWN":"蓮華。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그리 불러도 되겠나?","JPN":"そう呼んでもいいか？","ENG":"May I call you that?","TWN":"我可以這麼叫你嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"VOICE_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"VOICE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"기억해냈구나. 내 이름.","JPN":"思い出したのね、私の名前。","ENG":"So you remembered my name.","TWN":"你想起來了嗎，我的名字？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대의 뒷모습을 볼 때마다 궁금했다네.","JPN":"そなたの背中を見るたびに、気になっていたのだ。","ENG":"Every time I saw your back, I wondered.","TWN":"每次看到你的背影，我都會很好奇。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"기억을 두고 떠나야 했던 지난 날에… 무엇이 있었는지.","JPN":"記憶を置き去りにするしかなかった過去に……何があったのか。","ENG":"About what I left behind… when I chose to forget.","TWN":"在必須放下記憶離開的那些日子裡…到底發生什麼事。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"범이라 불리는 괴물이 있어.","JPN":"虎と呼ばれる化け物がいるわ。","ENG":"There's a monster called the Tiger.","TWN":"有一隻被稱為老虎的怪物。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"죽어도 죽지 않는 불사의 짐승. 녀석을 목숨을 걸고 막는 게 우리 사명이었지.","JPN":"死んでも死なない不死のケモノ……やつを命がけで引き止めるのが私たちの使命だった。","ENG":"An immortal Beast. Our mission was to stop it, no matter what.","TWN":"牠一隻死不透的野獸，而我們的使命就是用生命去阻止他。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"안 그러면 정말 많은 사람들이 죽었을 테니까.","JPN":"そうしないと、たくさんの人が命を落としていた。","ENG":"Otherwise, countless people would've died.","TWN":"否則會有很多人因此喪命。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그래서 내가 범을 죽이고, 나도 함께 죽었어. 그게 범을 막을 유일한 방법이었거든.","JPN":"だから私が虎を殺して、私も一緒に死んだのよ。それが虎を止める唯一の方法だったから。","ENG":"So I killed the Tiger and died with it. That was the only way.","TWN":"所以我殺了老虎後也一起賠上性命。但這是唯一能阻止牠的辦法。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"죽었다고…?","JPN":"死んだ……？","ENG":"You died…?","TWN":"你死了…？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"누군가 희생을 해야 했던 거라면, 그게 나일 순 없었던 건가?","JPN":"誰かの犠牲が必要だったのなら、某ではいけなかったのか？","ENG":"If someone had to sacrifice himself, why couldn't it have been me?","TWN":"如果有人必須犧牲，那個人為什麼不能是我？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신은 범을 상대하기엔 너무 약해. 몸도, 마음도.","JPN":"あなたは虎を相手するには弱すぎるわ。体も、心もね。","ENG":"You were too weak to face it. In body and in heart.","TWN":"你身心都太虛弱，無法對付老虎。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하지만 결국 범은 다시 돌아올 거야.","JPN":"でも、虎はまた戻ってくるはずよ。","ENG":"But the Tiger will return.","TWN":"但老虎終究會再次回來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"돌아온다고?","JPN":"戻ってくる？","ENG":"Return?","TWN":"會回來？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"기억해?","JPN":"覚えているかしら？","ENG":"Do you remember?","TWN":"你還記得嗎？"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신 친구의 목숨을 앗아간 그날의 검은 먹비를.","JPN":"あなたの友の命を奪った、あの日の墨雨を。","ENG":"That black Ink Rain that took your friend's life.","TWN":"那天奪走你朋友性命的黑色墨雨。"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"먹비는 범이 흘리는 피.","JPN":"墨雨は虎が流す血。","ENG":"That rain is the Tiger's blood.","TWN":"墨雨是老虎流下的血。"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 피엔 강한 저주가 서려, 비를 맞은 이의 혼을 물어 뜯고 인과의 양분으로 삼아.","JPN":"その血は強力な呪いを宿していて、雨に降られた者の魂を食いちぎり、因果の糧とするわ。","ENG":"That blood carries a deep curse. It devours souls affected by the rain and feeds on causality.","TWN":"那血帶著強大的詛咒，會啃食淋到墨雨的人的靈魂，並將他們的因果作為養分。"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 사람들이 희생될수록, 놈의 부활도 가까워지는 거야.","JPN":"そうやって犠牲になった人が増えるにつれて、やつの復活も近づいてくる。","ENG":"The more people it claims, the closer its return.","TWN":"就這樣，犧牲的人越多，牠復活的日子就越近。"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대가 없다면… 무슨 수로 그 괴물을 막지?","JPN":"そなたがいない世界で……どうすればその化け物を止められる？","ENG":"With you gone… How can I stop that monster?","TWN":"但沒有你…我該怎麼阻止那個怪物？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신은 과거에서 나를 만났고, 이미 그 진전을 이뤄냈어.","JPN":"あなたは過去で私に出会い、すでに進歩を遂げているわ。","ENG":"You met me in the past, and you already found the answer.","TWN":"你在過去遇見我後就已經找到方法了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"모든 걸 잊고 도망치는 대신, 이렇게 내 이름을 다시 기억해냈으니까.","JPN":"すべてを忘れて逃げる代わりに、こうして私の名前を思い出してくれたのだから。","ENG":"Instead of choosing to forget and run, you remembered my name.","TWN":"因為你沒有選擇忘記和逃跑，而是像這樣再次記起了我的名字。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"만약 당신이 모든 걸 잊고 도망치더라도, 과거의 나라면 그 선택이 틀렸다고 말하지 않겠지.","JPN":"もしあなたが逃げたとしても、過去の私ならその選択を非難したりはしないでしょう。","ENG":"If it were the past me… I would have embraced you. Even if you had run away.","TWN":"我相信過去的我…依舊會溫暖地擁抱逃跑的你。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"난 당신이 과거에 얽매이지 않았으면 했고. 아픈 기억 때문에 슬퍼하지 않길 바랐으니까.","JPN":"あなたが辛い記憶に囚われないように、私たちの死に悲しまないように……私はそう願っていたから。","ENG":"So that you wouldn't drown in painful memory. So you wouldn't mourn our death.","TWN":"因為不希望你被痛苦的記憶束縛，不希望你為我們的死感到悲傷。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이젠 우리 모두 알고 있잖아.","JPN":"でも、もう分かったでしょう。","ENG":"But now we all know.","TWN":"但我們現在都很清楚，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"묻고 잊어버리는 것만으론 곁에 있는 사람들을 지킬 수 없단 걸.","JPN":"記憶に蓋をして忘れ去ることでは、側にいる人は守れないってこと。","ENG":"Forgetting and burying the past won't protect anyone.","TWN":"埋葬和遺忘，是無法保護身邊的人的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"과거로부터 내 죽음을 없던 것으로 바꾼다면, 이번에도 내가 범을 막을 수 있어.","JPN":"過去を変えて私の死をなかったことにすれば、今回も虎を止められるわ。","ENG":"If you rewrite the past and erase my death, then I can stop the Tiger again.","TWN":"如果能改變過去，讓我的死不存在，那這次我就可以再次阻止老虎。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 전까지의 모든 건… 당신에게 달려 있는 거야.","JPN":"それまでのすべては……あなたの手にかかっている。","ENG":"Until then… everything depends on you.","TWN":"在那之前的一切…都取決於你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};